import { useState } from "react"
import './App.css';

export const TodoList = () => {
  const [incompleteTodos, setincompleteTodos] = useState(
    ["Todo1", "Todo2"]
  );
  const [completeTodos, setcompleteTodos] = useState(
    ["CompleteTodo1", "CompleteTodo2"]
  );

  return (
    <>
    <div>
      <input placeholder='Todoを入力'/>
      <button>追加</button>
    </div>
    <div>
        <p>未完了のToDo</p>
        <ul>
          {incompleteTodos.map((todo) => (
          <li key={todo}>
            <p>{todo}</p>
            <button>完了</button>
            <button>削除</button>
          </li>
            )
          )}
        </ul>
    </div>
    <div>
    <p>完了のToDo</p>
        <ul>
          <li>
            <p>completedです</p>
            <button>戻す</button>
          </li>
        </ul>
    </div>
    </>
  );
};
